    else if(ln.startsWith('## ')) blocks.push(mk('heading_2',ln.slice(3)));
    else if(ln.startsWith('# ')) blocks.push(mk('heading_1',ln.slice(2)));
    else { for(let i=0;i<ln.length;i+=1900) blocks.push(mk('paragraph',ln.slice(i,i+1900))); }
  }
  const first=blocks.slice(0,100);
  const cp=await this.helpers.httpRequest({method:'POST',url:'https://api.notion.com/v1/pages',headers:NHEAD,body:JSON.stringify({
    parent:{database_id:DB06},
    properties:{'жҳҺзҙ°еҗҚзЁұ':{title:[{text:{content:('рҹ“„ '+(pk.pdf_name||'PDF')).slice(0,200)}}]},'жҳҺзҙ°йЎһеһӢ':{select:{name:'иіҮж–ҷеҸғиҖғ'}},'еҸғиҖғйЎһеҲҘ':{select:{name:'дјҒеҠғеҸғиҖғ'}}},
    children:first})});
  const cpr=(typeof cp==='string')?JSON.parse(cp):cp;
  const pid=(cpr.id||'').replace(/-/g,'');
  for(let i=100;i<blocks.length;i+=100){
    try{await this.helpers.httpRequest({method:'PATCH',url:'https://api.notion.com/v1/blocks/'+pid+'/children',headers:NHEAD,body:JSON.stringify({children:blocks.slice(i,i+100)})});}catch(e){}
  }
  const tp=await this.helpers.httpRequest({method:'GET',url:'https://api.notion.com/v1/pages/'+pk.target_id,headers:NHEAD});
  const tpr=(typeof tp==='string')?JSON.parse(tp):tp;
  const ex=(((tpr.properties||{})['жҳҺзҙ°еј•з”Ё']||{}).relation||[]).map(x=>({id:x.id}));
  ex.push({id:pid});
  await this.helpers.httpRequest({method:'PATCH',url:'https://api.notion.com/v1/pages/'+pk.target_id,headers:NHEAD,body:JSON.stringify({properties:{'жҳҺзҙ°еј•з”Ё':{relation:ex}}})});
  note='PDF '+(pk.pdf_name||'')+' е·ІиҪүж–Үеӯ—('+md.length+' еӯ—)гҖҒе»әжҲҗиіҮж–ҷеҸғиҖғдёҰйҖЈе…Ҙ target жҳҺзҙ°еј•з”Ё';
}catch(err){ note='PDF иҷ•зҗҶеӨұж•—пјҡ'+(err&&err.message||err); }
return [{json:{pdf_note:note}}];
